import Foundation

public protocol StatusConnector: Sendable {
    var vendor: Vendor { get }
    func fetchOutages() async throws -> [Outage]
}

public enum StatusConnectorError: Error, CustomStringConvertible {
    case unexpectedResponse(statusCode: Int, url: String)
    case networkError(underlying: Error, url: String)
    case parseError(underlying: Error, url: String)
    case invalidURL(rawValue: String)

    public var description: String {
        switch self {
        case let .unexpectedResponse(code, url):
            "Status endpoint returned HTTP \(code) for \(url)"
        case let .networkError(err, url):
            "Status endpoint network error for \(url): \(err)"
        case let .parseError(err, url):
            "Status endpoint parse error for \(url): \(err)"
        case let .invalidURL(raw):
            "Invalid status endpoint URL: \(raw)"
        }
    }
}

import Foundation

// MARK: - Root

/// The top-level file model: `{ usages: [...], outages?: [...] }`.
///
/// `outages` is an optional sibling written by an upstream status-fetching process.
/// When no incident is ongoing the upstream writer is expected to drop the key
/// entirely; the encoder here honours that convention by emitting nothing when
/// the in-memory array is empty.
public struct UsagesFile: Codable, Equatable, Sendable {
    public var usages: [VendorUsageEntry]
    public var outages: [Outage]

    public init(usages: [VendorUsageEntry] = [], outages: [Outage] = []) {
        self.usages = usages
        self.outages = outages
    }

    /// Grouped view for the UI — vendors without outages are omitted.
    public var outagesByVendor: [Vendor: [Outage]] {
        Dictionary(grouping: outages, by: \.vendor)
    }

    private enum CodingKeys: String, CodingKey {
        case usages, outages
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        usages = try container.decodeIfPresent([VendorUsageEntry].self, forKey: .usages) ?? []
        outages = try container.decodeIfPresent([Outage].self, forKey: .outages) ?? []
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encode(usages, forKey: .usages)
        // Upstream convention: absent key when no ongoing outage — mirror that on write
        // so the file never carries a stale empty array between incidents.
        if !outages.isEmpty {
            try container.encode(outages, forKey: .outages)
        }
    }
}

// MARK: - VendorUsageEntry

public struct VendorUsageEntry: Codable, Equatable, Sendable, Identifiable {
    public var id: String { "\(vendor.rawValue):\(account.rawValue)" }

    public let vendor: Vendor
    public let account: AccountEmail
    public var isActive: Bool
    public var lastAcquiredOn: ISODate?
    public var lastError: UsageError?
    public var metrics: [UsageMetric]

    public init(
        vendor: Vendor,
        account: AccountEmail,
        isActive: Bool = false,
        lastAcquiredOn: ISODate? = nil,
        lastError: UsageError? = nil,
        metrics: [UsageMetric] = []
    ) {
        self.vendor = vendor
        self.account = account
        self.isActive = isActive
        self.lastAcquiredOn = lastAcquiredOn
        self.lastError = lastError
        self.metrics = metrics
    }
}

// MARK: - Error

public struct UsageError: Codable, Equatable, Sendable {
    public let timestamp: ISODate
    public let type: String

    public init(timestamp: ISODate, type: String) {
        self.timestamp = timestamp
        self.type = type
    }
}

// MARK: - Outage

/// An active incident on a vendor's platform, written by an upstream status-fetching process.
/// The upstream writer removes entries as incidents resolve, so a missing or empty
/// `outages` array means "all clear".
public struct Outage: Codable, Equatable, Sendable, Identifiable {
    public let vendor: Vendor
    public let errorMessage: String
    public let severity: OutageSeverity
    public let since: ISODate
    public let href: URL?

    /// Composite id — outages have no stable upstream id in this shape, so we
    /// derive one from the fields that together identify a single incident row.
    public var id: String {
        "\(vendor.rawValue)|\(since.rawValue)|\(href?.absoluteString ?? "")"
    }

    public init(
        vendor: Vendor,
        errorMessage: String,
        severity: OutageSeverity,
        since: ISODate,
        href: URL? = nil
    ) {
        self.vendor = vendor
        self.errorMessage = errorMessage
        self.severity = severity
        self.since = since
        self.href = href
    }

    private enum CodingKeys: String, CodingKey {
        case vendor, errorMessage, severity, since, href
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        vendor = try container.decode(Vendor.self, forKey: .vendor)
        errorMessage = try container.decode(String.self, forKey: .errorMessage)
        severity = try container.decode(OutageSeverity.self, forKey: .severity)
        since = try container.decode(ISODate.self, forKey: .since)
        if let hrefString = try container.decodeIfPresent(String.self, forKey: .href) {
            guard let parsed = URL(string: hrefString) else {
                throw DecodingError.dataCorruptedError(
                    forKey: .href, in: container,
                    debugDescription: "Invalid URL string: \(hrefString)")
            }
            href = parsed
        } else {
            href = nil
        }
    }
}

// MARK: - Metric (polymorphic on "type" discriminator)

public enum UsageMetric: Codable, Equatable, Sendable {
    case timeWindow(name: String, resetAt: ISODate?, windowDuration: DurationMinutes, usagePercent: UsagePercent)
    case payAsYouGo(name: String, currentAmount: Double, currency: String)
    /// A metric type not yet known to this client; retained for round-trip fidelity.
    case unknown(String)

    // MARK: Kind

    public var kind: MetricKind {
        switch self {
        case .timeWindow:       .timeWindow
        case .payAsYouGo:       .payAsYouGo
        case .unknown(let t):   .unknown(t)
        }
    }

    // MARK: Coding

    private enum CodingKeys: String, CodingKey {
        case type, name, resetAt
        case windowDuration = "windowDurationMinutes"
        case usagePercent, currentAmount, currency
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        let metricKind = try container.decode(MetricKind.self, forKey: .type)
        switch metricKind {
        case .timeWindow:
            self = .timeWindow(
                name: try container.decode(String.self, forKey: .name),
                resetAt: try container.decodeIfPresent(ISODate.self, forKey: .resetAt),
                windowDuration: try container.decode(DurationMinutes.self, forKey: .windowDuration),
                usagePercent: try container.decode(UsagePercent.self, forKey: .usagePercent)
            )
        case .payAsYouGo:
            self = .payAsYouGo(
                name: try container.decode(String.self, forKey: .name),
                currentAmount: try container.decode(Double.self, forKey: .currentAmount),
                currency: try container.decode(String.self, forKey: .currency)
            )
        case .unknown(let t):
            self = .unknown(t)
        }
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        switch self {
        case let .timeWindow(name, resetAt, windowDuration, usagePercent):
            try container.encode(MetricKind.timeWindow, forKey: .type)
            try container.encode(name, forKey: .name)
            try container.encodeIfPresent(resetAt, forKey: .resetAt)
            try container.encode(windowDuration, forKey: .windowDuration)
            try container.encode(usagePercent, forKey: .usagePercent)
        case let .payAsYouGo(name, currentAmount, currency):
            try container.encode(MetricKind.payAsYouGo, forKey: .type)
            try container.encode(name, forKey: .name)
            try container.encode(currentAmount, forKey: .currentAmount)
            try container.encode(currency, forKey: .currency)
        case let .unknown(t):
            // Only the type discriminator round-trips; unknown fields are not preserved
            try container.encode(MetricKind.unknown(t), forKey: .type)
        }
    }
}

import SwiftUI
import AppKit
import AIUsagesTrackersLib

enum VendorBranding {
    struct Brand: Equatable, Sendable {
        let assetName: String
        let displayName: String
        let tintHex: String
    }

    static func brand(for vendor: Vendor) -> Brand? {
        switch vendor {
        case .claude:
            Brand(
                assetName: "claude-mark",
                displayName: "Claude Code",
                tintHex: "DA7756"
            )
        case .codex:
            Brand(
                assetName: "codex-mark",
                displayName: "Codex",
                tintHex: "10A37F"
            )
        default:
            nil
        }
    }

    static func displayName(for vendor: Vendor) -> String {
        brand(for: vendor)?.displayName ?? vendor.rawValue
    }

    static func tint(for vendor: Vendor) -> Color? {
        guard let tintHex = brand(for: vendor)?.tintHex else { return nil }
        return Color(hex: tintHex)
    }

    static func icon(for vendor: Vendor) -> NSImage? {
        guard let assetName = brand(for: vendor)?.assetName else { return nil }
        return loadTemplateImage(named: assetName)
    }

    /// Pixels of white halo added on each side around the vendor icon for legibility.
    static let iconGlowPadding: CGFloat = 3.0

    /// Returns a tinted, non-template copy of the vendor icon at the requested height.
    /// Uses the brand's `tintHex` as fill color and the template PDF as an alpha mask.
    /// A crisp white halo is produced by drawing a white silhouette at pixel offsets
    /// in all directions — no blur, so the icon stays sharp on any menu bar tint color.
    @MainActor
    static func tintedNSImage(for vendor: Vendor, height: CGFloat) -> NSImage? {
        guard let template = icon(for: vendor),
              let brand = brand(for: vendor),
              let tintColor = NSColor(hex: brand.tintHex) else { return nil }
        let aspectRatio = template.size.height > 0
            ? template.size.width / template.size.height : 1
        let iconSize = NSSize(width: ceil(height * aspectRatio), height: ceil(height))
        let pad = Self.iconGlowPadding
        let canvasSize = NSSize(width: iconSize.width + pad * 2, height: iconSize.height + pad * 2)
        let iconRect = NSRect(x: pad, y: pad, width: iconSize.width, height: iconSize.height)

        let tinted = NSImage(size: iconSize)
        tinted.lockFocus()
        tintColor.setFill()
        NSRect(origin: .zero, size: iconSize).fill()
        template.draw(
            in: NSRect(origin: .zero, size: iconSize),
            from: .zero,
            operation: .destinationIn,
            fraction: 1.0
        )
        tinted.unlockFocus()

        let white = NSImage(size: iconSize)
        white.lockFocus()
        NSColor.white.setFill()
        NSRect(origin: .zero, size: iconSize).fill()
        template.draw(
            in: NSRect(origin: .zero, size: iconSize),
            from: .zero,
            operation: .destinationIn,
            fraction: 1.0
        )
        white.unlockFocus()

        let result = NSImage(size: canvasSize)
        result.lockFocus()
        // Draw the white silhouette at every surrounding pixel offset to build a crisp halo.
        for dx: CGFloat in [-2, -1, 0, 1, 2] {
            for dy: CGFloat in [-2, -1, 0, 1, 2] where !(dx == 0 && dy == 0) {
                white.draw(in: NSRect(
                    x: iconRect.minX + dx, y: iconRect.minY + dy,
                    width: iconRect.width, height: iconRect.height
                ))
            }
        }
        tinted.draw(in: iconRect)
        result.unlockFocus()
        result.isTemplate = false
        return result
    }

    /// Resolves the SwiftPM resource bundle without ever touching `Bundle.module`,
    /// whose synthesized accessor traps with a precondition failure when the
    /// expected `.bundle` is missing next to the executable. We probe every
    /// location the bundle may legitimately land in across `swift run`,
    /// `swift build`, the assembled `.app`, and merged-into-main-bundle layouts —
    /// returning `nil` instead of crashing the app when none match.
    private static let resourceBundleName = "AIUsagesTrackers_AIUsagesTrackers"

    private static let resourceBundle: Bundle? = {
        let bundleFile = "\(resourceBundleName).bundle"
        let mainURL = Bundle.main.bundleURL
        let tokenBundle = Bundle(for: BundleToken.self)
        let candidates: [URL?] = [
            Bundle.main.resourceURL,
            mainURL,
            mainURL.appendingPathComponent("Contents/MacOS"),
            mainURL.appendingPathComponent("Contents/Resources"),
            tokenBundle.resourceURL,
            tokenBundle.bundleURL,
        ]
        for candidate in candidates.compactMap({ $0 }) {
            let bundleURL = candidate.appendingPathComponent(bundleFile)
            if let bundle = Bundle(url: bundleURL) {
                return bundle
            }
        }
        return nil
    }()

    private static func loadTemplateImage(named assetName: String) -> NSImage? {
        let url = locateAsset(named: assetName, fileExtension: "pdf", subdirectory: "VendorBranding")
        guard let url, let image = NSImage(contentsOf: url) else { return nil }
        image.isTemplate = true
        return image
    }

    private static func locateAsset(
        named assetName: String,
        fileExtension: String,
        subdirectory: String
    ) -> URL? {
        if let url = Bundle.main.url(
            forResource: assetName,
            withExtension: fileExtension,
            subdirectory: subdirectory
        ) {
            return url
        }
        if let url = resourceBundle?.url(
            forResource: assetName,
            withExtension: fileExtension,
            subdirectory: subdirectory
        ) {
            return url
        }
        return nil
    }
}

private final class BundleToken {}

struct VendorIconView: View {
    let vendor: Vendor
    var size: CGFloat = 14

    var body: some View {
        if let image = VendorBranding.icon(for: vendor),
           let tint = VendorBranding.tint(for: vendor) {
            Image(nsImage: image)
                .renderingMode(.template)
                .resizable()
                .scaledToFit()
                .frame(width: size, height: size)
                .foregroundStyle(tint)
                .accessibilityHidden(true)
        } else {
            // Asset bundle missing (defensive fallback): show the vendor's first
            // letter so the rest of the UI stays informative instead of blank.
            Text(VendorBranding.displayName(for: vendor).prefix(1).uppercased())
                .font(.system(size: size * 0.8, weight: .semibold))
                .foregroundStyle(VendorBranding.tint(for: vendor) ?? .primary)
                .frame(width: size, height: size)
                .accessibilityHidden(true)
        }
    }
}

struct VendorLabelView: View {
    let vendor: Vendor
    var iconSize: CGFloat = 14

    var body: some View {
        HStack(spacing: 6) {
            VendorIconView(vendor: vendor, size: iconSize)
            Text(VendorBranding.displayName(for: vendor))
        }
    }
}

private extension Color {
    init?(hex: String) {
        guard hex.count == 6, let value = Int(hex, radix: 16) else { return nil }

        let red = Double((value >> 16) & 0xFF) / 255.0
        let green = Double((value >> 8) & 0xFF) / 255.0
        let blue = Double(value & 0xFF) / 255.0

        self.init(red: red, green: green, blue: blue)
    }
}

private extension NSColor {
    convenience init?(hex: String) {
        guard hex.count == 6, let value = Int(hex, radix: 16) else { return nil }

        let red = CGFloat((value >> 16) & 0xFF) / 255.0
        let green = CGFloat((value >> 8) & 0xFF) / 255.0
        let blue = CGFloat(value & 0xFF) / 255.0

        self.init(red: red, green: green, blue: blue, alpha: 1.0)
    }
}

